mapper.select:
SELECT t.*, CAST(t.overdue_days * 0.5 AS DECIMAL(10, 2)) AS dynamic_fine FROM ( SELECT br.id, br.user_id, br.book_id, br.borrow_time, br.due_time, br.return_time, br.renew_time, br.renew_count, br.status, u.username, u.real_name, u.student_no, b.isbn, b.title AS book_title, b.author AS book_author, b.cover_url, CASE WHEN br.status = 2 THEN CASE WHEN DATEDIFF(br.return_time, br.due_time) > 0 THEN DATEDIFF(br.return_time, br.due_time) ELSE 0 END WHEN br.status = 3 THEN DATEDIFF(NOW(), br.due_time) WHEN br.due_time < NOW() AND br.status IN (0, 1) THEN DATEDIFF(NOW(), br.due_time) ELSE 0 END AS overdue_days FROM borrow_record br LEFT JOIN sys_user u ON br.user_id = u.id AND u.is_deleted = 0 LEFT JOIN book_info b ON br.book_id = b.id AND b.is_deleted = 0 WHERE br.is_deleted = 0
AND br.user_id = #{userId}
AND (u.username LIKE CONCAT('%', #{username}, '%') OR u.real_name LIKE CONCAT('%', #{username}, '%'))
AND br.status = #{status}
AND (b.title LIKE CONCAT('%', #{bookKeyword}, '%') OR b.isbn LIKE CONCAT('%', #{bookKeyword}, '%'))
ORDER BY br.create_time DESC LIMIT #{offset}, #{limit} ) t

SELECT COUNT(*) FROM borrow_record br LEFT JOIN sys_user u ON br.user_id = u.id AND u.is_deleted = 0 LEFT JOIN book_info b ON br.book_id = b.id AND b.is_deleted = 0 WHERE br.is_deleted = 0
AND br.user_id = #{userId}
AND (u.username LIKE CONCAT('%', #{username}, '%') OR u.real_name LIKE CONCAT('%', #{username}, '%'))
AND br.status = #{status}
AND (b.title LIKE CONCAT('%', #{bookKeyword}, '%') OR b.isbn LIKE CONCAT('%', #{bookKeyword}, '%'))

SELECT COUNT(*) FROM borrow_record
WHERE user_id = #{userId} AND book_id = #{bookId}
  AND status IN (0, 1, 3) AND is_deleted = 0

SELECT CAST(status AS SIGNED) AS status, COUNT(*) AS cnt FROM borrow_record WHERE is_deleted = 0
AND user_id = #{userId}
GROUP BY status
